package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressArrayConstructorSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // array_constructor
  // =========================================================================
  test("array_constructor") {
    assertCompresses(
      input = """console.log(new Array());
        console.log(new Array(0));
        console.log(new Array(1));
        console.log(new Array(11));
        console.log(new Array(12))""".stripMargin.trim,
      expected = """console.log(new Array());
        console.log(new Array(0));
        console.log(new Array(1));
        console.log(new Array(11));
        console.log(new Array(12))""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // array_constructor_unsafe
  // =========================================================================
  test("array_constructor_unsafe") {
    assertCompresses(
      input = """console.log(new Array());
        console.log(new Array(0));
        console.log(new Array(1));
        console.log(new Array(11));
        console.log(Array(11));
        console.log(new Array(12));
        console.log(Array(12));
        console.log(new Array(foo));
        console.log(Array(foo));
        console.log(new Array("foo"));
        console.log(Array("foo"))""".stripMargin.trim,
      expected = """console.log([]);
        console.log([]);
        console.log([,]);
        console.log([,,,,,,,,,,,]);
        console.log([,,,,,,,,,,,]);
        console.log(Array(12));
        console.log(Array(12));
        console.log(Array(foo));
        console.log(Array(foo));
        console.log(Array("foo"));
        console.log(Array("foo"))""".stripMargin.trim,
      options = AllOff.copy(
        unsafe = true
      )
    )
  }

}
